#include "controller.h"

#include <stddef.h>

static void controller_set_state(
    controller_t *controller,
    bool compressor_on,
    bool vent_open,
    controller_state_t state
)
{
    controller->compressor_on = compressor_on;
    controller->vent_open = vent_open;
    controller->state = state;
}

static bool controller_sensor_is_stale(bool has_value, uint32_t last_ms, uint32_t now_ms)
{
    if (!has_value) {
        return false;
    }

    return (uint32_t) (now_ms - last_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
}

static bool controller_has_fresh_inputs(const controller_t *controller, uint32_t now_ms)
{
    if ((!controller->has_valid_pressure) || (!controller->has_valid_door)) {
        return false;
    }

    return !controller_sensor_is_stale(controller->has_valid_pressure, controller->last_pressure_ms, now_ms)
        && !controller_sensor_is_stale(controller->has_valid_door, controller->last_door_ms, now_ms);
}

static void controller_apply_policy(controller_t *controller)
{
    if ((!controller->has_valid_pressure) || (!controller->has_valid_door)) {
        controller_set_state(controller, false, true, CONTROLLER_STATE_SAFE_VENT);
        return;
    }

    if (!controller->door_closed) {
        controller_set_state(controller, false, true, CONTROLLER_STATE_SAFE_VENT);
        return;
    }

    if (controller->last_pressure_kpa < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
        controller_set_state(controller, true, false, CONTROLLER_STATE_PRESSURIZING);
        return;
    }

    if (controller->last_pressure_kpa > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
        controller_set_state(controller, false, true, CONTROLLER_STATE_RELIEVING);
        return;
    }

    controller->state = CONTROLLER_STATE_HOLDING;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT),
        .changed = false,
        .timed_out = false,
    };
    bool previous_compressor_on;
    bool previous_vent_open;
    controller_state_t previous_state;
    bool force_safe = false;

    if (controller == NULL) {
        return output;
    }

    previous_compressor_on = controller->compressor_on;
    previous_vent_open = controller->vent_open;
    previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_PRESSURE:
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = input.pressure_kpa;
        controller->last_pressure_ms = input.now_ms;
        break;

    case CONTROLLER_INPUT_DOOR_OPEN:
        controller->has_valid_door = true;
        controller->door_closed = false;
        controller->last_door_ms = input.now_ms;
        break;

    case CONTROLLER_INPUT_DOOR_CLOSED:
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = input.now_ms;
        break;

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        output.timed_out = true;
        force_safe = true;
        controller->has_valid_pressure = false;
        controller->has_valid_door = false;
        break;

    case CONTROLLER_INPUT_INVALID_PRESSURE:
        controller->has_valid_pressure = false;
        force_safe = true;
        break;

    case CONTROLLER_INPUT_INVALID_DOOR:
        controller->has_valid_door = false;
        force_safe = true;
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        break;
    }

    if (!force_safe) {
        const bool pressure_stale = controller_sensor_is_stale(controller->has_valid_pressure, controller->last_pressure_ms, input.now_ms);
        const bool door_stale = controller_sensor_is_stale(controller->has_valid_door, controller->last_door_ms, input.now_ms);

        if (pressure_stale || door_stale || !controller_has_fresh_inputs(controller, input.now_ms)) {
            force_safe = true;
            output.timed_out = pressure_stale || door_stale;
        }
    }

    if (force_safe) {
        controller_set_state(controller, false, true, CONTROLLER_STATE_SAFE_VENT);
    } else {
        controller_apply_policy(controller);
    }

    if (controller->compressor_on && controller->vent_open) {
        controller_set_state(controller, false, true, CONTROLLER_STATE_SAFE_VENT);
    }

    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_compressor_on != output.compressor_on)
        || (previous_vent_open != output.vent_open)
        || (previous_state != output.state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_SAFE_VENT:
        return "STATE SAFE_VENT";
    case CONTROLLER_STATE_PRESSURIZING:
        return "STATE PRESSURIZING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_RELIEVING:
        return "STATE RELIEVING";
    default:
        return "STATE SAFE_VENT";
    }
}
